import numpy as np

def compute_phase(dr, dc, d):
    if d == 0:
        return 0
    if dr == -d and dc >= 0:
        return dc
    elif dc == d and dr > -d:
        return d + (dr + d)
    elif dr == d:
        return 3*d + (d - dc)
    elif dc == -d:
        return 5*d + (d - dr)
    elif dr == -d and dc < 0:
        return 7*d + (dc + d)
    return -1

def solve(grid):
    H, W = len(grid), len(grid[0])
    positions = [(r,c) for r in range(H) for c in range(W) if grid[r][c] == 8]
    rows = [p[0] for p in positions]
    cols = [p[1] for p in positions]
    cr = (min(rows) + max(rows)) // 2
    cc = (min(cols) + max(cols)) // 2
    N = cr - min(rows)  # arm length

    M = max(N, 2)
    W_break = max(1, N - 1)

    output = [[0]*W for _ in range(H)]

    for r in range(H):
        for c in range(W):
            dr, dc = r - cr, c - cc
            d = max(abs(dr), abs(dc))

            if d == 0:
                output[r][c] = 0
                continue

            phase = compute_phase(dr, dc, d)

            if d < M:
                output[r][c] = 8 if phase % 2 == 0 else 0
            else:
                majority = 8 if (d % 2) == (M % 2) else 0
                minority = 0 if majority == 8 else 8

